class Solution:
    def countSubsequences(self, arr: list[int], k: int) -> int:
        n = len(arr)
        count = 0
        for mask in range(1 << n):
            subsequence_sum = 0
            for i in range(n):
                if (mask & (1 << i)):
                    subsequence_sum += arr[i]
            if subsequence_sum == k:
                count += 1
        return count
