#include <numeric>

#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int countSubsequences(vector<int>& arr, int k) {
        int n = arr.size();
        int count = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            int subsequence_sum = 0;
            for (int i = 0; i < n; i++) {
                if (mask & (1 << i)) {
                    subsequence_sum += arr[i];
                }
            }
            if (subsequence_sum == k) {
                count++;
            }
        }
        return count;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.countSubsequences(arr, k);
    cout << ans << endl;
    return 0;
}
